function sanitizeSlackMrkdwn(text) {
  return String(text || '')
    .replace(/```\w*\n?/g, '```')
    .replace(/^#{1,6}\s+(.+)$/gm, '*$1*')
    .replace(/^[-*_]{3,}\s*$/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>')
    .replace(/\n{3,}/g, '\n\n');
}

const raw = (($json.output || [])[0]?.content || []).find(c => c.type === 'output_text')?.text || '';
const date = new Date().toISOString().slice(0, 10);
const header = '*Social Content \u2014 ' + date + '*';
const footer = '_Thread router: reply with a persona name for a focused take._';
if (!raw.trim()) {
  return [{ json: { formatted: sanitizeSlackMrkdwn(':warning: No output generated. Check workflow logs.\n\n' + footer) } }];
}
let body;
try {
  const obj = JSON.parse(raw);
  body = Object.entries(obj).map(([k, v]) => {
    const label = k.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    if (Array.isArray(v)) {
      return '\u2022 *' + label + '*:\n' + v.map(item => '  - ' + (typeof item === 'object' ? JSON.stringify(item) : item)).join('\n');
    }
    if (typeof v === 'object' && v !== null) {
      return '\u2022 *' + label + '*: ' + JSON.stringify(v);
    }
    return '\u2022 *' + label + '*: ' + v;
  }).join('\n');
} catch (e) {
  body = raw;
}
return [{ json: { formatted: sanitizeSlackMrkdwn(header + '\n\n' + body + '\n\n' + footer) } }];
